import {
  Skeleton,
  Stack,
  type Theme,
  Tooltip,
  Typography,
} from "@mui/material";

import { CompanyAvatar, type CompanyAvatarColor } from "./CompanyAvatar.tsx";

type Props = {
  imgSrc?: string | null;
  name: string;
  size?: keyof Theme["avatarSize"];
  color?: CompanyAvatarColor | number;
  truncateText?: boolean;
  subtitle?: string;
};

export const CompanyAvatarWithLabel = ({
  imgSrc,
  name,
  size = 32,
  color,
  truncateText = false,
  subtitle,
}: Props) => {
  return (
    <Stack direction="row" alignItems="center" gap={1.5}>
      <CompanyAvatar imgSrc={imgSrc} name={name} size={size} color={color} />
      <Stack>
        {truncateText ? (
          <Tooltip title={name} placement="top">
            <Typography
              variant="body2"
              sx={{
                ...(size >= 32 && { fontWeight: 600 }),
                maxWidth: "140px",
                overflow: "hidden",
                textOverflow: "ellipsis",
                whiteSpace: "nowrap",
              }}
            >
              {name}
            </Typography>
          </Tooltip>
        ) : (
          <Typography
            variant="body2"
            sx={{
              ...(size >= 32 && { fontWeight: 600 }),
            }}
          >
            {name}
          </Typography>
        )}
        {subtitle && <Typography variant="body2">{subtitle}</Typography>}
      </Stack>
    </Stack>
  );
};

type SkeletonProps = {
  size?: keyof Theme["avatarSize"];
};

export const CompanyAvatarWithLabelSkeleton = ({
  size = 32,
}: SkeletonProps) => {
  return (
    <Stack direction="row" alignItems="center" gap={1.5}>
      <Skeleton
        variant="rectangular"
        sx={(theme) => ({
          ...theme.avatarSize[size],
        })}
      />
      <Skeleton variant="text" sx={{ width: 100, height: 24 }} />
    </Stack>
  );
};

